// ProjectAI.js
import React, {
  useState,
  useEffect,
  useRef,
  useCallback,
  useMemo,
} from "react";
import "./ProjectAI.css";

// ============================================
// SMART CHIPS (per tab)
// ============================================
const getChipsForTab = (tabName) => {
  const base = {
    "README.md": [
      "⚡ 30-second pitch",
      "What problem does it solve?",
      "What's unique about it?",
    ],
    "PROBLEM.md": [
      "Why does this matter?",
      "Who felt the pain?",
      "How was it solved?",
    ],
    "SOLUTION.md": [
      "Explain the architecture",
      "Why this tech stack?",
      "Biggest challenge?",
    ],
    "tech-stack.json": [
      "Why these tools?",
      "Any trade-offs?",
      "What would you change?",
    ],
    "impact.md": ["Key metrics?", "What did you learn?", "What's next?"],
  };
  return base[tabName] || base["README.md"];
};

// ============================================
// PROJECT BRAIN — instant answers grounded in
// the project's own portfolio data. No API, no
// latency, works offline and on any device.
// ============================================
const cleanTitle = (name = "") =>
  name
    .replace(/[\p{Extended_Pictographic}️‍]/gu, "")
    .replace(/\s{2,}/g, " ")
    .split(/\s+—\s+|\s+-\s+/)[0]
    .trim();

const bullets = (items, max = 4) =>
  (items || [])
    .slice(0, max)
    .map((s) => `• ${s}`)
    .join("\n");

const joinLines = (lines) => lines.filter(Boolean).join("\n");

const INTENTS = [
  {
    id: "links",
    test: /demo|link|github|live|repo\b|video|screenshot|source code|where can i (see|try)/i,
    tab: "screenshots",
    followUps: ["⚡ 30-second pitch", "Key metrics?"],
    answer: (p, d) => {
      const isGitHub = p.url?.includes("github.com");
      return joinLines([
        "Where to see it 🔗",
        "",
        `• ${isGitHub ? "Source code" : "Live platform"}: ${p.url}`,
        d.demoVideo ? "• Demo video: available in the demo tab" : null,
        "",
        "The screenshots and demo files in the explorer have more visuals.",
      ]);
    },
  },
  {
    id: "tech",
    test: /tech|stack|tools?\b|languages?|framework|built with|why these/i,
    tab: "tech-stack.json",
    followUps: ["Explain the architecture", "Any trade-offs?"],
    answer: (p, d) => {
      const cats = d.techStack
        ? Object.entries(d.techStack).map(
            ([cat, techs]) =>
              `• ${cat.charAt(0).toUpperCase() + cat.slice(1)}: ${techs
                .map((t) => t.name || t)
                .join(", ")}`
          )
        : [
            `• ${(p.languages || []).map((l) => l.name).join(", ")}`,
          ];
      return joinLines([
        "The stack, layer by layer 🛠️",
        "",
        ...cats,
        "",
        "Open tech-stack.json in the explorer for the full breakdown.",
      ]);
    },
  },
  {
    id: "architecture",
    test: /architect|data flow|pipeline|under the hood|how (does|did) (it|this|data)|how it works|design/i,
    tab: "SOLUTION.md",
    followUps: ["Why this tech stack?", "Biggest challenge?"],
    answer: (p, d) =>
      joinLines([
        "How it works under the hood 🏗️",
        "",
        d.story?.solution || d.solution || p.description,
        d.architectureHighlights?.length ? "" : null,
        d.architectureHighlights?.length
          ? "Key engineering decisions:"
          : null,
        bullets(d.architectureHighlights, 4),
        "",
        "There's an interactive architecture diagram in SOLUTION.md.",
      ]),
  },
  {
    id: "impact",
    test: /impact|results?|metric|success|numbers?|kpi|outcome|achiev|measure/i,
    tab: "impact.md",
    followUps: ["What did you learn?", "What's next?"],
    answer: (p, d) =>
      joinLines([
        "The numbers that matter 📈",
        "",
        bullets(d.impact, 5) || "Impact details are in the impact.md tab.",
      ]),
  },
  {
    id: "next",
    test: /what'?s next|future|roadmap|plan(s|ned)?\b/i,
    tab: "impact.md",
    followUps: ["Key metrics?", "⚡ 30-second pitch"],
    answer: (p, d) => {
      const ongoing = /present/i.test(
        typeof d.timeline === "string" ? d.timeline : ""
      );
      return joinLines([
        ongoing
          ? "It's live and actively evolving 🚀"
          : "Shipped — and full of lessons 🚀",
        "",
        ongoing
          ? "The system runs in production and keeps improving. Current focus areas come straight from what building it taught:"
          : "The project is complete; the takeaways now feed into newer work:",
        bullets(d.learnings, 3),
      ]);
    },
  },
  {
    id: "challenge",
    test: /challeng|difficult|hard(est)?\b|learn|trade-?offs?|would you change|improve|mistake|do differently/i,
    tab: "impact.md",
    followUps: ["Key metrics?", "Explain the architecture"],
    answer: (p, d) =>
      joinLines([
        "Hard parts & lessons 💡",
        "",
        bullets(d.learnings, 4) ||
          "The trickiest part was balancing reliability with speed of iteration.",
      ]),
  },
  {
    id: "unique",
    test: /unique|different|special|stand ?out|why not just|compare|vs\b/i,
    tab: "README.md",
    followUps: ["Key metrics?", "Explain the architecture"],
    answer: (p, d) =>
      joinLines([
        "What makes it stand out ✨",
        "",
        bullets(d.features, 4) || bullets(d.impact, 3) || p.description,
      ]),
  },
  {
    id: "roleteam",
    test: /\brole\b|team|who built|solo|how long|duration|when (was|did)|timeline/i,
    tab: "README.md",
    followUps: ["⚡ 30-second pitch", "Biggest challenge?"],
    answer: (p, d) =>
      joinLines([
        "Role & ownership 👤",
        "",
        d.role ? `• Role: ${d.role}` : null,
        d.team ? `• Team: ${d.team}` : null,
        typeof d.timeline === "string" ? `• Timeline: ${d.timeline}` : null,
      ]),
  },
  {
    id: "hire",
    test: /hire|recruit|interview|why (should|would)|impress/i,
    tab: "impact.md",
    followUps: ["Key metrics?", "Explain the architecture"],
    answer: (p, d) =>
      joinLines([
        "Fair question 😄 Here's the evidence:",
        "",
        d.role ? `• Owned it end-to-end as ${d.role}` : null,
        bullets(d.impact, 3),
        "",
        "The Contact page is the fastest way to reach Laxman.",
      ]),
  },
  {
    id: "problem",
    test: /problem|why (was|does|is|did)|important|matter|pain|broken|before|need(ed)?\b|existing solution|who felt/i,
    tab: "PROBLEM.md",
    followUps: ["How was it solved?", "Key metrics?"],
    answer: (p, d) =>
      joinLines([
        "The problem it tackles 🔍",
        "",
        d.story?.problem || d.problem || p.description,
        d.newsLinks?.length
          ? `\n📰 The problem was real enough that the solution was covered by ${d.newsLinks
              .map((l) => l.source)
              .join(" and ")}.`
          : null,
      ]),
  },
  {
    id: "solution",
    test: /solv|solution|how was it|approach|fix(ed)?\b/i,
    tab: "SOLUTION.md",
    followUps: ["Explain the architecture", "Key metrics?"],
    answer: (p, d) =>
      joinLines([
        "The solution ✅",
        "",
        d.story?.solution || d.solution || p.description,
      ]),
  },
  {
    id: "summary",
    test: /summar|overview|pitch|about|tell me|what (is|does)|explain|elevator|nutshell|30/i,
    tab: "README.md",
    followUps: ["What problem does it solve?", "Key metrics?"],
    answer: (p, d) =>
      joinLines([
        `${cleanTitle(p.name)} in 30 seconds 🎯`,
        "",
        p.description,
        "",
        d.role
          ? `👤 ${d.role}${
              typeof d.timeline === "string" ? ` · ${d.timeline}` : ""
            }`
          : null,
        d.impact?.[0] ? `🏆 ${d.impact[0]}` : null,
      ]),
  },
];

const answerQuestion = (question, project) => {
  const d = project?.details || {};
  const intent = INTENTS.find((i) => i.test.test(question));
  if (intent) {
    return {
      text: intent.answer(project, d),
      tab: intent.tab,
      followUps: intent.followUps,
    };
  }
  return {
    text: joinLines([
      `Good question! I know ${cleanTitle(
        project?.name
      )} inside out — the problem, the architecture, the stack, the results.`,
      "",
      "Try one of the suggestions below, or ask about any of those areas.",
    ]),
    tab: null,
    followUps: ["⚡ 30-second pitch", "Explain the architecture", "Key metrics?"],
  };
};

// ============================================
// NARRATOR SCRIPT
// ============================================
const getNarratorScript = (project) => {
  const d = project?.details || {};
  return [
    {
      title: "Intro",
      text: `Let me tell you about ${project.name}. ${project.description}`,
      tab: "README.md",
    },
    {
      title: "Problem",
      text: `So, here's the problem it solves. ${
        d.story?.problem ||
        d.problem ||
        "This project addresses a real-world challenge."
      }`,
      tab: "PROBLEM.md",
    },
    {
      title: "Solution",
      text: `And here's how I solved it. ${
        d.story?.solution ||
        d.solution ||
        "I built a solution using modern technologies."
      }`,
      tab: "SOLUTION.md",
    },
    {
      title: "Tech",
      text: `For the tech stack, I used ${
        project.languages?.map((l) => l.name).join(", and ") ||
        "modern technologies"
      }. Each was chosen for a specific reason.`,
      tab: "tech-stack.json",
    },
    {
      title: "Impact",
      text: `Now for the results. ${
        d.impact?.[0] || "This project made a meaningful impact."
      }`,
      tab: "impact.md",
    },
  ];
};

// ============================================
// VOICE HELPERS
// ============================================
const PREFERRED_VOICES = [
  "Microsoft Aria Online (Natural)",
  "Microsoft Jenny Online (Natural)",
  "Microsoft Guy Online (Natural)",
  "Microsoft Ana Online (Natural)",
  "Google US English",
  "Google UK English Female",
  "Google UK English Male",
  "Samantha",
  "Karen",
  "Daniel",
  "Moira",
  "Microsoft Zira",
  "Microsoft David",
  "Alex",
];

const getBestVoice = (voices) => {
  for (const name of PREFERRED_VOICES) {
    const match = voices.find((v) => v.name.includes(name));
    if (match) return match;
  }
  return (
    voices.find((v) => v.lang === "en-US") ||
    voices.find((v) => v.lang.startsWith("en")) ||
    voices[0]
  );
};

const humanizeText = (text) => {
  return text
    .replace(/[\u{1F600}-\u{1F64F}]/gu, "")
    .replace(/[\u{1F300}-\u{1F5FF}]/gu, "")
    .replace(/[\u{1F680}-\u{1F6FF}]/gu, "")
    .replace(/[\u{1F1E0}-\u{1F1FF}]/gu, "")
    .replace(/[\u{2600}-\u{26FF}]/gu, "")
    .replace(/[\u{2700}-\u{27BF}]/gu, "")
    .replace(/[\u{FE00}-\u{FE0F}]/gu, "")
    .replace(/[\u{1F900}-\u{1F9FF}]/gu, "")
    .replace(/[\u{1FA00}-\u{1FA6F}]/gu, "")
    .replace(/[\u{1FA70}-\u{1FAFF}]/gu, "")
    .replace(/[\u{200D}]/gu, "")
    .replace(/[\u{20E3}]/gu, "")
    .replace(/•/g, "")
    .replace(/\. /g, "... ")
    .replace(/, /g, ",  ")
    .replace(/: /g, "...  ")
    .replace(/; /g, "...  ")
    .replace(/(.{60,100}?[\.\,\;\:]) /g, "$1 ... ")
    .replace(/API/g, "A P I")
    .replace(/UI/g, "U I")
    .replace(/SQL/g, "sequel")
    .replace(/NoSQL/g, "no sequel")
    .replace(/AWS/g, "A W S")
    .replace(/GCP/g, "G C P")
    .replace(/CI\/CD/g, "C I C D")
    .replace(/REST/g, "rest")
    .replace(/MongoDB/g, "Mongo D B")
    .replace(/Node\.js/g, "Node JS")
    .replace(/React\.js/g, "React JS")
    .replace(/Next\.js/g, "Next JS")
    .replace(/HTML/g, "H T M L")
    .replace(/CSS/g, "C S S")
    .replace(/LLM/g, "L L M")
    .replace(/NLP/g, "N L P")
    .replace(/ML/g, "M L")
    .replace(/AI/g, "A I")
    .replace(/\s{3,}/g, "  ")
    .trim();
};

// ============================================
// Detect if device is truly mobile (touch + small screen)
// ============================================
const getIsMobile = () => {
  return (
    window.innerWidth <= 768 ||
    ("ontouchstart" in window && window.innerWidth <= 1024)
  );
};

const prefersReducedMotion = () =>
  typeof window !== "undefined" &&
  window.matchMedia &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

// ============================================
// TYPED MESSAGE — typewriter answer rendering
// ============================================
const TypedMessage = ({ text, instant, onTick, onDone }) => {
  const [shown, setShown] = useState(instant ? text : "");
  const doneRef = useRef(false);

  useEffect(() => {
    if (instant || prefersReducedMotion()) {
      setShown(text);
      if (!doneRef.current) {
        doneRef.current = true;
        onDone?.();
      }
      return;
    }
    doneRef.current = false;
    let i = 0;
    // Scale speed so long answers finish in ~2s
    const step = Math.max(1, Math.round(text.length / 130));
    const id = setInterval(() => {
      i = Math.min(text.length, i + step);
      setShown(text.slice(0, i));
      onTick?.();
      if (i >= text.length) {
        clearInterval(id);
        if (!doneRef.current) {
          doneRef.current = true;
          onDone?.();
        }
      }
    }, 16);
    return () => clearInterval(id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [text, instant]);

  return (
    <>
      {shown.split("\n").map((line, i) =>
        line.startsWith("• ") ? (
          <span key={i} className="ai-msg-bullet">
            <span className="ai-msg-bullet-dot">▸</span>
            {line.slice(2)}
          </span>
        ) : (
          <span key={i} className="ai-msg-line">
            {line}
          </span>
        )
      )}
    </>
  );
};

// ============================================
// MAIN COMPONENT
// ============================================
const ProjectAI = ({
  project,
  activeTab,
  scrollProgress,
  onTabChange,
  onOpenSiri,
  isVisible,
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [hasHinted, setHasHinted] = useState(false);
  const [showHint, setShowHint] = useState(false);
  const [hintDismissed, setHintDismissed] = useState(false);
  const [activeMode, setActiveMode] = useState("ask");
  const [isMobile, setIsMobile] = useState(getIsMobile());
  const [narratorPlaying, setNarratorPlaying] = useState(false);
  const [narratorStep, setNarratorStep] = useState(0);
  const [speechSupported, setSpeechSupported] = useState(true);
  const [narratorPaused, setNarratorPaused] = useState(false);

  // ---- Ask-mode state ----
  const [messages, setMessages] = useState([]); // {id, role: "user"|"ai", text, tab, followUps, done}
  const [inputValue, setInputValue] = useState("");
  const [isThinking, setIsThinking] = useState(false);

  // Refs
  const onTabChangeRef = useRef(onTabChange);
  const onOpenSiriRef = useRef(onOpenSiri);
  const hintTimer = useRef(null);
  const narratorTimer = useRef(null);
  const speechTimeout = useRef(null);
  const utteranceRef = useRef(null);
  const fallbackTimer = useRef(null);
  const keepAliveInterval = useRef(null);
  const narratorPlayingRef = useRef(false);
  const narratorStepRef = useRef(0);
  const conversationRef = useRef(null);
  const panelRef = useRef(null);
  const inputRef = useRef(null);
  const thinkTimer = useRef(null);
  const msgId = useRef(0);
  const touchStartY = useRef(null);

  const chips = useMemo(() => getChipsForTab(activeTab), [activeTab]);
  const narratorScript = useMemo(() => getNarratorScript(project), [project]);

  // Suggestions: follow-ups of the last answer, else tab-based chips
  const lastAI = [...messages].reverse().find((m) => m.role === "ai");
  const suggestions = lastAI?.done && lastAI.followUps?.length
    ? lastAI.followUps
    : chips;

  // Keep refs updated
  useEffect(() => {
    onTabChangeRef.current = onTabChange;
  }, [onTabChange]);
  useEffect(() => {
    onOpenSiriRef.current = onOpenSiri;
  }, [onOpenSiri]);
  useEffect(() => {
    narratorPlayingRef.current = narratorPlaying;
  }, [narratorPlaying]);
  useEffect(() => {
    narratorStepRef.current = narratorStep;
  }, [narratorStep]);

  // Fresh conversation when a different project opens
  useEffect(() => {
    setMessages([]);
    setInputValue("");
    setIsThinking(false);
  }, [project?.name]);

  // Mobile detection
  useEffect(() => {
    const check = () => setIsMobile(getIsMobile());
    window.addEventListener("resize", check);
    window.addEventListener("orientationchange", check);
    return () => {
      window.removeEventListener("resize", check);
      window.removeEventListener("orientationchange", check);
    };
  }, []);

  // Check speech synthesis support
  useEffect(() => {
    const synth = window.speechSynthesis;
    if (!synth) {
      setSpeechSupported(false);
      return;
    }
    const loadVoices = () => {
      synth.getVoices();
    };
    loadVoices();
    if (synth.onvoiceschanged !== undefined) {
      synth.onvoiceschanged = loadVoices;
    }
  }, []);

  // ============================================
  // ASK ENGINE
  // ============================================
  const scrollConversation = useCallback(() => {
    const el = conversationRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  }, []);

  const markDone = useCallback(
    (id) => {
      setMessages((prev) =>
        prev.map((m) => (m.id === id ? { ...m, done: true } : m))
      );
      scrollConversation();
    },
    [scrollConversation]
  );

  const ask = useCallback(
    (question) => {
      const q = question.trim();
      if (!q || !project) return;
      setInputValue("");
      const userMsg = { id: ++msgId.current, role: "user", text: q };
      setMessages((prev) => [...prev.slice(-10), userMsg]);
      setIsThinking(true);
      requestAnimationFrame(scrollConversation);

      // Brief "thinking" beat so the answer feels considered, not canned
      clearTimeout(thinkTimer.current);
      thinkTimer.current = setTimeout(() => {
        const a = answerQuestion(q, project);
        setIsThinking(false);
        setMessages((prev) => [
          ...prev,
          { id: ++msgId.current, role: "ai", ...a, done: false },
        ]);
        requestAnimationFrame(scrollConversation);
      }, 450);
    },
    [project, scrollConversation]
  );

  const handleSubmit = useCallback(
    (e) => {
      e.preventDefault();
      ask(inputValue);
    },
    [ask, inputValue]
  );

  const openTabFromAnswer = useCallback((tab) => {
    if (onTabChangeRef.current && tab) {
      onTabChangeRef.current(tab);
    }
  }, []);

  // Speak an answer aloud (reuses narrator voice pipeline)
  const speakText = useCallback((text) => {
    const synth = window.speechSynthesis;
    if (!synth) return;
    synth.cancel();
    const u = new SpeechSynthesisUtterance(humanizeText(text));
    utteranceRef.current = u;
    u.voice = getBestVoice(synth.getVoices());
    u.rate = 0.95;
    synth.speak(u);
  }, []);

  // ============================================
  // ADVANCE TO NEXT STEP (narrator)
  // ============================================
  const advanceNarrator = useCallback(() => {
    if (!narratorPlayingRef.current) return;
    const currentStep = narratorStepRef.current;
    const maxSteps = narratorScript.length;

    if (currentStep < maxSteps - 1) {
      setNarratorStep((p) => p + 1);
    } else {
      setNarratorPlaying(false);
      setNarratorStep(0);
      window.speechSynthesis?.cancel();
    }
  }, [narratorScript.length]);

  // ============================================
  // MOBILE KEEP-ALIVE WORKAROUND
  // Chrome mobile pauses speech synthesis when it
  // thinks the page is idle. This keeps it alive.
  // ============================================
  useEffect(() => {
    if (!narratorPlaying || !isMobile) {
      clearInterval(keepAliveInterval.current);
      return;
    }

    keepAliveInterval.current = setInterval(() => {
      const synth = window.speechSynthesis;
      if (synth && synth.speaking) {
        synth.pause();
        synth.resume();
      }
    }, 5000);

    return () => clearInterval(keepAliveInterval.current);
  }, [narratorPlaying, isMobile]);

  // ============================================
  // NARRATOR EFFECT — MOBILE-SAFE
  // ============================================
  useEffect(() => {
    if (!narratorPlaying) {
      clearTimeout(fallbackTimer.current);
      clearTimeout(narratorTimer.current);
      clearTimeout(speechTimeout.current);
      return;
    }

    const step = narratorScript[narratorStep];
    if (!step) {
      setNarratorPlaying(false);
      return;
    }

    // Switch tab with a small delay for mobile rendering
    const tabDelay = isMobile ? 150 : 50;
    setTimeout(() => {
      if (onTabChangeRef.current) {
        onTabChangeRef.current(step.tab);
      }
    }, tabDelay);

    const synth = window.speechSynthesis;

    // If speech is not supported, use timer-based fallback
    if (!synth || !speechSupported) {
      const wordCount = step.text.split(" ").length;
      const readingTime = Math.max(3000, wordCount * 300);
      fallbackTimer.current = setTimeout(() => {
        advanceNarrator();
      }, readingTime);
      return () => clearTimeout(fallbackTimer.current);
    }

    // Cancel any existing speech
    synth.cancel();

    speechTimeout.current = setTimeout(
      () => {
        if (!narratorPlayingRef.current) return;

        const voices = synth.getVoices();
        const voice = getBestVoice(voices);
        const humanText = humanizeText(step.text);

        const u = new SpeechSynthesisUtterance(humanText);
        utteranceRef.current = u;

        u.voice = voice;
        u.rate = isMobile ? 0.9 : 0.95;
        u.pitch = 1.0;
        u.volume = 1.0;

        let speechEnded = false;

        const handleEnd = () => {
          if (speechEnded) return;
          speechEnded = true;
          clearTimeout(fallbackTimer.current);

          narratorTimer.current = setTimeout(() => {
            advanceNarrator();
          }, 1200);
        };

        u.onend = handleEnd;

        u.onerror = (e) => {
          console.warn("Speech error:", e?.error || e);
          // On mobile, 'interrupted' errors are common and harmless
          if (e?.error === "interrupted") return;
          handleEnd();
        };

        // MOBILE FALLBACK: Set a maximum time per slide
        // If onend never fires (common on mobile), this ensures we advance
        const wordCount = humanText.split(" ").length;
        const estimatedDuration = Math.max(4000, wordCount * 350);
        const maxWait = estimatedDuration + 3000;

        fallbackTimer.current = setTimeout(() => {
          if (!speechEnded && narratorPlayingRef.current) {
            console.warn("Fallback timer triggered — advancing narrator");
            synth.cancel();
            handleEnd();
          }
        }, maxWait);

        try {
          synth.speak(u);

          // Double-check on mobile that speech actually started
          if (isMobile) {
            setTimeout(() => {
              if (
                !synth.speaking &&
                !speechEnded &&
                narratorPlayingRef.current
              ) {
                console.warn("Speech never started on mobile — using fallback");
                const fallbackTime = Math.max(3000, wordCount * 300);
                clearTimeout(fallbackTimer.current);
                fallbackTimer.current = setTimeout(() => {
                  handleEnd();
                }, fallbackTime);
              }
            }, 500);
          }
        } catch (err) {
          console.error("Speech synthesis error:", err);
          handleEnd();
        }
      },
      isMobile ? 400 : 200
    );

    return () => {
      clearTimeout(narratorTimer.current);
      clearTimeout(speechTimeout.current);
      clearTimeout(fallbackTimer.current);
    };
  }, [
    narratorStep,
    narratorPlaying,
    narratorScript,
    isMobile,
    speechSupported,
    advanceNarrator,
  ]);

  // ---- Hint (shows once) ----
  useEffect(() => {
    if (hasHinted || hintDismissed) return;
    hintTimer.current = setTimeout(() => {
      setShowHint(true);
      setHasHinted(true);
      setTimeout(() => setShowHint(false), 6000);
    }, 9000);
    return () => clearTimeout(hintTimer.current);
  }, [hasHinted, hintDismissed]);

  // ---- Handlers ----
  const dismissHint = useCallback(() => {
    setShowHint(false);
    setHintDismissed(true);
    clearTimeout(hintTimer.current);
  }, []);

  const toggleExpand = useCallback(() => {
    setIsExpanded((prev) => !prev);
    dismissHint();
  }, [dismissHint]);

  const closePanel = useCallback(() => {
    setIsExpanded(false);
    if (panelRef.current) panelRef.current.style.transform = "";
  }, []);

  const startNarrator = useCallback(() => {
    // On mobile, we need a user gesture to unlock audio
    if (isMobile && window.speechSynthesis) {
      const unlock = new SpeechSynthesisUtterance("");
      unlock.volume = 0;
      window.speechSynthesis.speak(unlock);
      window.speechSynthesis.cancel();
    }

    setNarratorStep(0);
    setNarratorPlaying(true);
    setNarratorPaused(false);
    setIsExpanded(false);
  }, [isMobile]);

  const stopNarrator = useCallback(() => {
    setNarratorPlaying(false);
    setNarratorPaused(false);
    setNarratorStep(0);
    clearTimeout(narratorTimer.current);
    clearTimeout(speechTimeout.current);
    clearTimeout(fallbackTimer.current);
    clearInterval(keepAliveInterval.current);
    window.speechSynthesis?.cancel();
  }, []);

  const togglePauseNarrator = useCallback(() => {
    const synth = window.speechSynthesis;
    if (!synth) return;

    if (narratorPaused) {
      synth.resume();
      setNarratorPaused(false);
    } else {
      synth.pause();
      setNarratorPaused(true);
    }
  }, [narratorPaused]);

  const skipToNext = useCallback(() => {
    window.speechSynthesis?.cancel();
    clearTimeout(narratorTimer.current);
    clearTimeout(fallbackTimer.current);
    advanceNarrator();
  }, [advanceNarrator]);

  const skipToPrev = useCallback(() => {
    if (narratorStep > 0) {
      window.speechSynthesis?.cancel();
      clearTimeout(narratorTimer.current);
      clearTimeout(fallbackTimer.current);
      setNarratorStep((p) => p - 1);
    }
  }, [narratorStep]);

  // ---- Swipe-down to close (mobile bottom sheet) ----
  const onSheetTouchStart = useCallback((e) => {
    touchStartY.current = e.touches[0].clientY;
  }, []);

  const onSheetTouchMove = useCallback((e) => {
    if (touchStartY.current === null || !panelRef.current) return;
    const dy = e.touches[0].clientY - touchStartY.current;
    if (dy > 0) {
      panelRef.current.style.transform = `translateY(${dy}px)`;
    }
  }, []);

  const onSheetTouchEnd = useCallback(
    (e) => {
      if (touchStartY.current === null) return;
      const dy = e.changedTouches[0].clientY - touchStartY.current;
      touchStartY.current = null;
      if (dy > 70) {
        closePanel();
      } else if (panelRef.current) {
        panelRef.current.style.transition = "transform 0.2s ease";
        panelRef.current.style.transform = "";
        setTimeout(() => {
          if (panelRef.current) panelRef.current.style.transition = "";
        }, 220);
      }
    },
    [closePanel]
  );

  // ---- Escape to close ----
  useEffect(() => {
    const handleKey = (e) => {
      if (e.key === "Escape") {
        if (narratorPlaying) stopNarrator();
        else closePanel();
      }
      // Arrow keys for narrator navigation
      if (narratorPlaying) {
        if (e.key === "ArrowRight") skipToNext();
        if (e.key === "ArrowLeft") skipToPrev();
        if (e.key === " ") {
          e.preventDefault();
          togglePauseNarrator();
        }
      }
    };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [
    closePanel,
    stopNarrator,
    narratorPlaying,
    skipToNext,
    skipToPrev,
    togglePauseNarrator,
  ]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      clearTimeout(narratorTimer.current);
      clearTimeout(speechTimeout.current);
      clearTimeout(fallbackTimer.current);
      clearInterval(keepAliveInterval.current);
      clearTimeout(hintTimer.current);
      clearTimeout(thinkTimer.current);
    };
  }, []);

  if (!isVisible) return null;

  // ============================================
  // RENDER
  // ============================================
  return (
    <div className="project-ai-wrapper">
      {/* ---- Subtle hint ---- */}
      {showHint && !isExpanded && !narratorPlaying && (
        <div className="ai-hint" onClick={toggleExpand} role="status">
          <span>✨</span>
          <span className="ai-hint-text">
            Ask me anything about this project
          </span>
          <button
            className="ai-hint-dismiss"
            onClick={(e) => {
              e.stopPropagation();
              dismissHint();
            }}
            aria-label="Dismiss"
          >
            ✕
          </button>
        </div>
      )}

      {/* ---- Narrator floating bar (when playing but panel closed) ---- */}
      {narratorPlaying && !isExpanded && (
        <div
          className={`ai-narrator-bar ${isMobile ? "mobile" : ""} ${
            narratorPaused ? "paused" : ""
          }`}
        >
          <div
            className={`narrator-mini-wave ${narratorPaused ? "paused" : ""}`}
          >
            {[...Array(4)].map((_, i) => (
              <span key={i} className="mini-wave-bar" />
            ))}
          </div>

          <div className="narrator-bar-info">
            <span className="narrator-bar-title">
              {narratorScript[narratorStep]?.title}
            </span>
            <span className="narrator-bar-step-count">
              {narratorStep + 1} / {narratorScript.length}
            </span>
          </div>

          <div className="narrator-bar-progress">
            {narratorScript.map((_, i) => (
              <span
                key={i}
                className={`progress-dot ${
                  i === narratorStep ? "active" : i < narratorStep ? "done" : ""
                }`}
              />
            ))}
          </div>

          <div className="narrator-bar-controls">
            <button
              className="narrator-ctrl-btn"
              onClick={skipToPrev}
              disabled={narratorStep === 0}
              aria-label="Previous step"
            >
              ⏮
            </button>

            <button
              className="narrator-ctrl-btn pause-btn"
              onClick={togglePauseNarrator}
              aria-label={narratorPaused ? "Resume" : "Pause"}
            >
              {narratorPaused ? "▶" : "⏸"}
            </button>

            <button
              className="narrator-ctrl-btn"
              onClick={skipToNext}
              aria-label="Next step"
            >
              ⏭
            </button>

            <button
              className="narrator-bar-stop"
              onClick={stopNarrator}
              aria-label="Stop narration"
            >
              ⏹
            </button>
          </div>
        </div>
      )}

      {/* ---- AI Pill Button ---- */}
      {!narratorPlaying && (
        <button
          className={`ai-pill ${isExpanded ? "active" : ""}`}
          onClick={toggleExpand}
          aria-label={isExpanded ? "Close AI" : "Open AI"}
          aria-expanded={isExpanded}
        >
          <span className="ai-pill-icon">✦</span>
          <span className="ai-pill-label">ASK AI</span>
        </button>
      )}

      {/* ---- Expanded Panel ---- */}
      {isExpanded && (
        <>
          <div
            className={`ai-backdrop ${isMobile ? "mobile" : ""}`}
            onClick={closePanel}
          />

          <div className={`ai-panel ${isMobile ? "mobile" : ""}`} ref={panelRef}>
            {/* Drag handle for mobile — swipe down to close */}
            {isMobile && (
              <div
                className="ai-panel-drag-handle"
                onTouchStart={onSheetTouchStart}
                onTouchMove={onSheetTouchMove}
                onTouchEnd={onSheetTouchEnd}
              >
                <div className="drag-bar" />
              </div>
            )}

            <div
              className="ai-panel-header"
              onTouchStart={isMobile ? onSheetTouchStart : undefined}
              onTouchMove={isMobile ? onSheetTouchMove : undefined}
              onTouchEnd={isMobile ? onSheetTouchEnd : undefined}
            >
              <div className="ai-panel-title">
                <span>✦</span>
                <span>JARVIS</span>
                <span className="ai-panel-context">{activeTab}</span>
              </div>
              <button
                className="ai-panel-close"
                onClick={closePanel}
                aria-label="Close"
              >
                ✕
              </button>
            </div>

            <div className="ai-panel-modes">
              <button
                className={activeMode === "ask" ? "active" : ""}
                onClick={() => setActiveMode("ask")}
              >
                💬 Ask
              </button>
              <button
                className={activeMode === "narrator" ? "active" : ""}
                onClick={() => setActiveMode("narrator")}
              >
                🎙️ Present
              </button>
              <button
                onClick={() => {
                  closePanel();
                  if (onOpenSiriRef.current) onOpenSiriRef.current();
                }}
              >
                🧠 Voice
              </button>
            </div>

            <div className="ai-panel-body">
              {/* ============ ASK MODE ============ */}
              {activeMode === "ask" && (
                <div className="ai-ask-section">
                  <div className="ai-conversation" ref={conversationRef}>
                    {messages.length === 0 && !isThinking && (
                      <div className="ai-welcome">
                        <span className="ai-welcome-icon">✦</span>
                        <p>
                          I know this project inside out — the problem, the
                          architecture, the results. Tap a question or type
                          your own.
                        </p>
                      </div>
                    )}

                    {messages.map((m) =>
                      m.role === "user" ? (
                        <div key={m.id} className="ai-msg ai-msg-user">
                          {m.text}
                        </div>
                      ) : (
                        <div key={m.id} className="ai-msg ai-msg-ai">
                          <TypedMessage
                            text={m.text}
                            instant={m.done}
                            onTick={scrollConversation}
                            onDone={() => markDone(m.id)}
                          />
                          {m.done && (
                            <div className="ai-msg-actions">
                              {m.tab && m.tab !== activeTab && (
                                <button
                                  className="ai-msg-action"
                                  onClick={() => openTabFromAnswer(m.tab)}
                                >
                                  📂 Open {m.tab}
                                </button>
                              )}
                              {speechSupported && (
                                <button
                                  className="ai-msg-action"
                                  onClick={() => speakText(m.text)}
                                  aria-label="Read answer aloud"
                                >
                                  🔊 Listen
                                </button>
                              )}
                            </div>
                          )}
                        </div>
                      )
                    )}

                    {isThinking && (
                      <div className="ai-msg ai-msg-ai ai-thinking">
                        <span className="think-dot" />
                        <span className="think-dot" />
                        <span className="think-dot" />
                      </div>
                    )}
                  </div>

                  <div className="ai-suggestions">
                    {suggestions.map((chip, i) => (
                      <button
                        key={`${chip}-${i}`}
                        className="ai-chip"
                        onClick={() => ask(chip)}
                        style={{ animationDelay: `${i * 0.05}s` }}
                      >
                        {chip}
                      </button>
                    ))}
                  </div>

                  <form className="ai-input-row" onSubmit={handleSubmit}>
                    <input
                      ref={inputRef}
                      type="text"
                      className="ai-input"
                      placeholder="Ask about this project…"
                      value={inputValue}
                      onChange={(e) => setInputValue(e.target.value)}
                      aria-label="Ask a question about this project"
                    />
                    <button
                      type="submit"
                      className="ai-send-btn"
                      disabled={!inputValue.trim()}
                      aria-label="Send question"
                    >
                      ➤
                    </button>
                  </form>
                </div>
              )}

              {/* ============ PRESENT MODE ============ */}
              {activeMode === "narrator" && (
                <div className="ai-narrator-section">
                  {!speechSupported && (
                    <div className="narrator-warning">
                      ⚠️ Voice not available on this device. Will use
                      auto-advance instead.
                    </div>
                  )}
                  <div className="narrator-steps">
                    {narratorScript.map((step, i) => (
                      <div key={i} className="narrator-step">
                        <div className="narrator-step-dot" />
                        <span>{step.title}</span>
                      </div>
                    ))}
                  </div>
                  <button
                    className="narrator-start-btn"
                    onClick={startNarrator}
                  >
                    ▶ Auto-present this project
                  </button>
                  <p className="narrator-note">
                    {isMobile
                      ? "A guided voice tour — it walks through every tab for you"
                      : "A guided voice tour — the panel closes so you can watch each tab as it narrates"}
                  </p>
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default ProjectAI;
