/** "CAMS Lens 🔍 — SEBI-Grounded Platform" → { emoji, title, tagline } */
const parseProjectName = (name = "") => {
  const emojiMatch = name.match(/\p{Extended_Pictographic}️?/u);
  const emoji = emojiMatch ? emojiMatch[0] : null;
  const clean = name
    .replace(/[\p{Extended_Pictographic}️‍]/gu, "")
    .replace(/\s{2,}/g, " ")
    .trim();
  const parts = clean.split(/\s+—\s+|\s+-\s+/);
  if (parts.length >= 2) {
    return {
      emoji,
      title: parts[0].trim(),
      tagline: parts.slice(1).join(" — ").trim(),
    };
  }
  return { emoji, title: clean, tagline: "" };
};

/** "95% retrieval precision" → { value: 95, suffix: "%", label: "retrieval precision" } */
const parseImpactMetric = (sentence) => {
  if (!sentence) return null;
  const m = sentence.match(/([~<>≈]?)(\$?)([\d][\d,.]*)\s*(%|\+|x|X|k\+?|K\+?|M\+?)?/);
  if (!m) return null;
  let label = sentence.replace(m[0], "").replace(/\s+/g, " ").trim();
  label = label.replace(/^[-–—:,.\s]+|[-–—:,.\s]+$/g, "");
  if (label.length > 60) label = label.slice(0, 57) + "…";
  const numbersInSentence = (sentence.match(/\d[\d,.]*/g) || []).length;
  return {
    value: parseFloat(m[3].replace(/,/g, "")),
    prefix: `${m[1]}${m[2]}`,
    suffix: m[4] || "",
    label,
    // Sentences with a single clean number make the best headline stats
    clean: numbersInSentence === 1,
  };
};

const STAT_ICONS = ["🎯", "⚡", "📊", "🚀", "🧠"];
const STAT_COLORS = ["#4fc3f7", "#4caf50", "#ffb74d", "#ab47bc", "#f44336"];

/** Build animated stat cards from details.stats, or derive them from details.impact */
const deriveStats = (details) => {
  if (details.stats?.length) return details.stats;
  const parsed = (details.impact || []).map(parseImpactMetric).filter(Boolean);
  const clean = parsed.filter((p) => p.clean);
  const picked = (clean.length >= 3 ? clean : parsed).slice(0, 4);
  return picked.map((p, i) => ({
    label: p.label,
    value: p.value,
    suffix: p.suffix,
    prefix: p.prefix,
    icon: STAT_ICONS[i % STAT_ICONS.length],
    color: STAT_COLORS[i % STAT_COLORS.length],
  }));
};

