/** Animated Stat Counter Card */
const StatCard = ({ label, value, suffix = "", prefix = "", icon, color }) => {
  const [ref, inView] = useInView({ threshold: 0.3 });
  const count = useAnimatedCounter(value, 1800, inView);
  const displayValue =
    typeof value === "string" && isNaN(parseInt(value))
      ? value
      : typeof count === "number"
      ? count.toLocaleString()
      : count;

  return (
    <div ref={ref} className="stat-card" style={{ "--stat-color": color }}>
      <div className="stat-icon">{icon}</div>
      <div className="stat-value">
        {prefix}
        {displayValue}
        {suffix}
      </div>
      <div className="stat-label">{label}</div>
      <div className="stat-bar">
        <div
          className="stat-bar-fill"
          style={{ width: inView ? "100%" : "0%" }}
        />
      </div>
    </div>
  );
};

/** Big animated headline number for the case-study hero */
const HeroMetric = ({ metric, delay = 0 }) => {
  const [ref, inView] = useInView({ threshold: 0.3 });
  const count = useAnimatedCounter(metric.value, 1600, inView);
  return (
    <div
      ref={ref}
      className="cs-hero-metric"
      style={{ animationDelay: `${delay}s` }}
    >
      <span className="cs-hero-metric-value">
        {metric.prefix}
        {typeof count === "number" ? count.toLocaleString() : count}
        {metric.suffix}
      </span>
      <span className="cs-hero-metric-label">{metric.label}</span>
    </div>
  );
};

