/** Notification Toast */
const Toast = ({ message, type = "info", onClose }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 3000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const icons = {
    info: <VscInfo />,
    success: <VscCheck />,
    warning: <VscWarning />,
    error: <VscError />,
  };

  return (
    <div className={`toast toast-${type}`}>
      <span className="toast-icon">{icons[type]}</span>
      <span className="toast-message">{message}</span>
      <button className="toast-close" onClick={onClose}>
        <VscClose />
      </button>
    </div>
  );
};

/** Command Palette */
const CommandPalette = ({ commands, onSelect, onClose }) => {
  const [search, setSearch] = useState("");
  const inputRef = useRef(null);
  const [selectedIndex, setSelectedIndex] = useState(0);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const filtered = useMemo(
    () =>
      commands.filter(
        (cmd) =>
          cmd.label.toLowerCase().includes(search.toLowerCase()) ||
          cmd.category?.toLowerCase().includes(search.toLowerCase())
      ),
    [commands, search]
  );

  useEffect(() => {
    setSelectedIndex(0);
  }, [search]);

  const handleKeyDown = (e) => {
    switch (e.key) {
      case "ArrowDown":
        e.preventDefault();
        setSelectedIndex((prev) => Math.min(prev + 1, filtered.length - 1));
        break;
      case "ArrowUp":
        e.preventDefault();
        setSelectedIndex((prev) => Math.max(prev - 1, 0));
        break;
      case "Enter":
        if (filtered[selectedIndex]) {
          onSelect(filtered[selectedIndex]);
          onClose();
        }
        break;
      case "Escape":
        onClose();
        break;
      default:
        break;
    }
  };

  return (
    <div className="command-palette-overlay" onClick={onClose}>
      <div className="command-palette" onClick={(e) => e.stopPropagation()}>
        <div className="command-input-wrapper">
          <FaSearch className="command-search-icon" />
          <input
            ref={inputRef}
            type="text"
            placeholder="Type a command or search..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={handleKeyDown}
            className="command-input"
          />
          <kbd className="command-kbd">ESC</kbd>
        </div>
        <div className="command-list">
          {filtered.length === 0 ? (
            <div className="command-empty">No matching commands</div>
          ) : (
            filtered.map((cmd, i) => (
              <div
                key={cmd.id}
                className={`command-item ${
                  i === selectedIndex ? "selected" : ""
                }`}
                onClick={() => {
                  onSelect(cmd);
                  onClose();
                }}
                onMouseEnter={() => setSelectedIndex(i)}
              >
                <span className="command-item-icon">{cmd.icon}</span>
                <div className="command-item-text">
                  <span className="command-item-label">{cmd.label}</span>
                  {cmd.description && (
                    <span className="command-item-desc">{cmd.description}</span>
                  )}
                </div>
                {cmd.shortcut && (
                  <kbd className="command-shortcut">{cmd.shortcut}</kbd>
                )}
                {cmd.category && (
                  <span className="command-item-category">{cmd.category}</span>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

/** Minimap Component */
const Minimap = ({ contentRef }) => {
  const [viewportRatio, setViewportRatio] = useState({ top: 0, height: 0.3 });
  const minimapRef = useRef(null);

  useEffect(() => {
    const content = contentRef?.current;
    if (!content) return;

    const handleScroll = () => {
      const { scrollTop, scrollHeight, clientHeight } = content;
      const top = scrollTop / scrollHeight;
      const height = clientHeight / scrollHeight;
      setViewportRatio({ top, height: Math.min(height, 1) });
    };

    content.addEventListener("scroll", handleScroll);
    handleScroll();
    return () => content.removeEventListener("scroll", handleScroll);
  }, [contentRef]);

  const handleMinimapClick = (e) => {
    const content = contentRef?.current;
    if (!content || !minimapRef.current) return;
    const rect = minimapRef.current.getBoundingClientRect();
    const clickRatio = (e.clientY - rect.top) / rect.height;
    content.scrollTop = clickRatio * content.scrollHeight;
  };

  return (
    <div className="minimap" ref={minimapRef} onClick={handleMinimapClick}>
      <div className="minimap-content">
        {/* Simulated content lines */}
        {Array.from({ length: 60 }).map((_, i) => (
          <div
            key={i}
            className="minimap-line"
            style={{
              width: `${20 + Math.random() * 70}%`,
              opacity: i % 8 === 0 ? 0.6 : 0.25,
              height: i % 12 === 0 ? "3px" : "2px",
              marginTop: i % 12 === 0 ? "4px" : "1px",
            }}
          />
        ))}
      </div>
      <div
        className="minimap-viewport"
        style={{
          top: `${viewportRatio.top * 100}%`,
          height: `${viewportRatio.height * 100}%`,
        }}
      />
    </div>
  );
};

